class InvalidAgeException extends Exception {}

function checkAge($age) {
    if ($age < 0) {
        throw new InvalidAgeException("나이는 음수일 수 없습니다");
    }
    return $age;
}

try {
    checkAge(-5);
} catch (InvalidAgeException $e) {
    echo $e->getMessage();
}

